using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class ChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -5.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(string.Empty, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 25.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrEmpty(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_SmallestValidAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class RefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrEmpty(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_InvalidChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("charge_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(string.Empty));
    }

    [TestMethod]
    public async Task RefundAsync_DuplicateRefund_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);

        await _gateway.RefundAsync(charge.ChargeId);
        var duplicate = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(duplicate.Success);
    }

    [TestMethod]
    public async Task RefundAsync_ReturnsUniqueRefundId()
    {
        var charge1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var charge2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }
}

[TestClass]
public class PaymentGatewayIntegrationTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ChargeAndRefund_FullLifecycle_Succeeds()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75.00m);
        Assert.IsTrue(charge.Success);

        var refund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(refund.Success);
    }

    [TestMethod]
    public async Task MultipleCharges_AllReturnDistinctIds()
    {
        var tasks = Enumerable.Range(1, 5)
            .Select(i => _gateway.ChargeAsync("tok_valid_visa", i * 10.00m));

        var results = await Task.WhenAll(tasks);

        var ids = results.Select(r => r.ChargeId).ToList();
        Assert.AreEqual(ids.Count, ids.Distinct().Count(),
            "All charge IDs should be unique");
    }

    [TestMethod]
    public async Task RefundWithoutCharge_Fails()
    {
        var result = await _gateway.RefundAsync("charge_never_existed");

        Assert.IsFalse(result.Success);
    }
}

